import type { BridgeHandlers, BridgeHandlerName, BridgeResponse } from "./types/bridge.types";

declare global {
  interface Window {
    flutter_inappwebview?: {
      callHandler<T extends BridgeHandlerName>(
        handlerName: T,
        ...args: BridgeHandlers[T]['request'] extends Record<string, never>
          ? []
          : [BridgeHandlers[T]['request']]): Promise<BridgeHandlers[T]['response']>;
    };
  }
}

class FlutterBridge {
  private readonly isFlutterApp: boolean = false;

  constructor() {
    this.isFlutterApp =
      typeof window !== 'undefined' &&
      window.flutter_inappwebview !== undefined;
  }

  isAvailable(): boolean {
    return this.isFlutterApp;
  }

  private async callHandler<T extends BridgeHandlerName>(
    handlerName: T,
    ...args: BridgeHandlers[T]['request'] extends Record<string, never>
      ? []
      : [BridgeHandlers[T]['request']]
  ): Promise<BridgeHandlers[T]['response']> {

    ///Todo: Check if is Web not embedded to Flutter?


    // It's not flutter app
    if (!this.isAvailable()) {
      return {
        success: false,
        error: 'Flutter bridge not available',
        code: 'NOT_AVAILABLE',
      } as BridgeHandlers[T]['response'];
    }

    try {
      const result = await window.flutter_inappwebview!.callHandler(
        handlerName,
        ...(args as any),
      );
      return result;
    } catch (error) {
      console.error(`Error calling ${handlerName}:`, error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
        code: 'BRIDGE_ERROR',
      } as BridgeHandlers[T]['response'];
    }
  }

  private isSuccess<T>(
    response: BridgeResponse<T>,
  ): response is { success: true; data: T } {
    return response.success === true;
  }

  private unwrapResponse<T>(response: BridgeResponse<T>): T {
    if (this.isSuccess(response)) {
      return response.data;
    }
    throw new Error(response.error || 'Unknown error');
  }

  // ============================================
  // Public API Methods (all fully typed)
  // ============================================

  async openCamera(options: BridgeHandlers['openCamera']['request'] = {}) {
    return this.callHandler('openCamera', options);
  }

  async openGallery(options: BridgeHandlers['openGallery']['request'] = {}) {
    return this.callHandler('openGallery', options);
  }

  async getLocation(options: BridgeHandlers['getLocation']['request'] = {}) {
    return this.callHandler('getLocation', options);
  }

  async getUserInfo() {
    return this.callHandler('getUserInfo');
  }

  async share(options: BridgeHandlers['share']['request']) {
    return this.callHandler('share', options);
  }

  async setStorage(key: string, value: string) {
    return this.callHandler('setStorage', { key, value });
  }

  async getStorage(key: string) {
    return this.callHandler('getStorage', { key });
  }

  // ============================================
  // Unwrapped versions (throw on error)
  // ============================================

   async openCameraOrThrow(
    options: BridgeHandlers['openCamera']['request'] = {},
  ) {
    const response = await this.openCamera(options);
    return this.unwrapResponse(response);
  }

  async getUserInfoOrThrow() {
    const response = await this.getUserInfo();
    return this.unwrapResponse(response);
  }
}

export default new FlutterBridge();
